import { useState, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import StarWarsAPI from '../services/StarWarsAPI'
import Card from 'react-bootstrap/Card'
import CardBody from 'react-bootstrap/Card'
import Button from 'react-bootstrap/Button'
import { Link } from 'react-router-dom'
import Table from 'react-bootstrap/Table'

const Film = () => {
	const [film, setFilm] = useState()
	const { id } = useParams()

	const getFilm = async (id) => {
		const data = await StarWarsAPI.getFilm(id)
		// console.log("data", data);
		setFilm(data)
	}

    useEffect(() => {
		getFilm(id)
	}, [id])

	if (!film) {
		return <p>Loading...</p>
	}

    return (
		<>
		{film && (
				   <Card className="film">
					   {/* <Card.Img variant="top" src=""/> */}
					   <CardBody>
					   <Card.Title className="film-title">{film.title}</Card.Title>
					   <Card.Subtitle className="film-subtitle">Attributes</Card.Subtitle>
					   {/* <CardText className="film-info">
					   <p className="film-id film-space"><span>Episode</span> <span >{film.episode_id}</span></p>
					   <p className="film-director film-space"><span>Director</span> <span>{film.director}</span></p>
					   <p className="film-producer film-space"><span>Producer</span> <span>{film.producer}</span></p>
					   <p className="film-release film-space"><span>Released</span> <span>{film.release_date}</span></p>
					   {/* <p>{film.characters.length} characters</p> */}
					   {/* </CardText> */} 
					   <Table>
					   <tbody>
    						<tr>
      							<td>Episode</td>
      							<td>{film.episode_id}</td>
    						</tr>
    						<tr>
      							<td>Director</td>
      							<td>{film.director}</td>
    						</tr>
							<tr>
      							<td>Producer</td>
      							<td>{film.producer}</td>
    						</tr>
							<tr>
      							<td>Released</td>
      							<td>{film.release_date}</td>
    						</tr>
							<p className="film-links">Links</p>
							<tr>
      							<td>Characters</td>
								  {film.characters.map((character, index) =>
								  <td>
									<span as={Link} to={{character}}>Character {++index}</span>		
								  </td>
								  )}
    						</tr>
						</tbody>
					   </Table>
					   <Button variant="primary" as={Link} to={`/films`} className="film-goback">Go back</Button>
					   </CardBody>
				   </Card>


	   )} 

	   {!film && (
		   <p className="status">No film!</p>
	   )}
	   </>
	)
}

export default Film
